using System.IO.Abstractions;
using System.Text;

namespace MyApp.Services;

/// <summary>
/// Convenience wrapper over <see cref="IFileSystem"/> that provides
/// common file and directory operations with built-in safety checks.
/// </summary>
public interface IFileSystemWrapper
{
    string ReadAllText(string path);
    string ReadAllText(string path, Encoding encoding);
    byte[] ReadAllBytes(string path);
    string[] ReadAllLines(string path);

    void WriteAllText(string path, string contents, bool createDirectory = true);
    void WriteAllText(string path, string contents, Encoding encoding, bool createDirectory = true);
    void WriteAllBytes(string path, byte[] bytes, bool createDirectory = true);
    void WriteAllLines(string path, IEnumerable<string> lines, bool createDirectory = true);

    Stream OpenRead(string path);
    Stream OpenWrite(string path, bool createDirectory = true);

    bool FileExists(string path);
    bool DirectoryExists(string path);

    void EnsureDirectoryExists(string path);
    void DeleteFile(string path);
    void DeleteDirectory(string path, bool recursive = false);

    void CopyFile(string source, string destination, bool overwrite = false, bool createDirectory = true);
    void MoveFile(string source, string destination, bool overwrite = false, bool createDirectory = true);

    IEnumerable<string> EnumerateFiles(string path, string searchPattern = "*", SearchOption searchOption = SearchOption.TopDirectoryOnly);
    IEnumerable<string> EnumerateDirectories(string path, string searchPattern = "*", SearchOption searchOption = SearchOption.TopDirectoryOnly);

    string GetFullPath(string path);
    string Combine(params string[] paths);
}

public class FileSystemWrapper(IFileSystem fileSystem) : IFileSystemWrapper
{
    public string ReadAllText(string path) =>
        fileSystem.File.ReadAllText(path);

    public string ReadAllText(string path, Encoding encoding) =>
        fileSystem.File.ReadAllText(path, encoding);

    public byte[] ReadAllBytes(string path) =>
        fileSystem.File.ReadAllBytes(path);

    public string[] ReadAllLines(string path) =>
        fileSystem.File.ReadAllLines(path);

    public void WriteAllText(string path, string contents, bool createDirectory = true)
    {
        EnsureParentDirectory(path, createDirectory);
        fileSystem.File.WriteAllText(path, contents);
    }

    public void WriteAllText(string path, string contents, Encoding encoding, bool createDirectory = true)
    {
        EnsureParentDirectory(path, createDirectory);
        fileSystem.File.WriteAllText(path, contents, encoding);
    }

    public void WriteAllBytes(string path, byte[] bytes, bool createDirectory = true)
    {
        EnsureParentDirectory(path, createDirectory);
        fileSystem.File.WriteAllBytes(path, bytes);
    }

    public void WriteAllLines(string path, IEnumerable<string> lines, bool createDirectory = true)
    {
        EnsureParentDirectory(path, createDirectory);
        fileSystem.File.WriteAllLines(path, lines);
    }

    public Stream OpenRead(string path) =>
        fileSystem.File.OpenRead(path);

    public Stream OpenWrite(string path, bool createDirectory = true)
    {
        EnsureParentDirectory(path, createDirectory);
        return fileSystem.File.OpenWrite(path);
    }

    public bool FileExists(string path) =>
        fileSystem.File.Exists(path);

    public bool DirectoryExists(string path) =>
        fileSystem.Directory.Exists(path);

    public void EnsureDirectoryExists(string path)
    {
        if (!fileSystem.Directory.Exists(path))
            fileSystem.Directory.CreateDirectory(path);
    }

    public void DeleteFile(string path)
    {
        if (fileSystem.File.Exists(path))
            fileSystem.File.Delete(path);
    }

    public void DeleteDirectory(string path, bool recursive = false)
    {
        if (fileSystem.Directory.Exists(path))
            fileSystem.Directory.Delete(path, recursive);
    }

    public void CopyFile(string source, string destination, bool overwrite = false, bool createDirectory = true)
    {
        EnsureParentDirectory(destination, createDirectory);
        fileSystem.File.Copy(source, destination, overwrite);
    }

    public void MoveFile(string source, string destination, bool overwrite = false, bool createDirectory = true)
    {
        EnsureParentDirectory(destination, createDirectory);
        if (overwrite && fileSystem.File.Exists(destination))
            fileSystem.File.Delete(destination);
        fileSystem.File.Move(source, destination);
    }

    public IEnumerable<string> EnumerateFiles(string path, string searchPattern = "*", SearchOption searchOption = SearchOption.TopDirectoryOnly) =>
        fileSystem.Directory.EnumerateFiles(path, searchPattern, searchOption);

    public IEnumerable<string> EnumerateDirectories(string path, string searchPattern = "*", SearchOption searchOption = SearchOption.TopDirectoryOnly) =>
        fileSystem.Directory.EnumerateDirectories(path, searchPattern, searchOption);

    public string GetFullPath(string path) =>
        fileSystem.Path.GetFullPath(path);

    public string Combine(params string[] paths) =>
        fileSystem.Path.Combine(paths);

    private void EnsureParentDirectory(string filePath, bool create)
    {
        if (!create) return;
        var dir = fileSystem.Path.GetDirectoryName(filePath);
        if (!string.IsNullOrEmpty(dir) && !fileSystem.Directory.Exists(dir))
            fileSystem.Directory.CreateDirectory(dir);
    }
}

